 minmax(200px, 1fr)); gap: 12px; max-width: 650px; }             .zs-gallery-item { border: 1px solid #ddd; border-radius: 4px; overflow: hidden; background: #f9f9f9; aspect-ratio: 1; display: flex; align-items: center; justify-content: center; }             .zs-gallery-item img, .zs-gallery-item video { width: 100%; height: 100%; object-fit: cover; display: block; cursor: pointer; }             .zs-gallery-item a { display: block; width: 100%; height: 100%; }             .zs-lightbox { display: none; position: fixed; z-index: 999999; left: 0; top: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.9); align-items: center; justify-content: center; }             .zs-lightbox.active { display: flex; }             .zs-lightbox img { max-width: 90%; max-height: 90%; object-fit: contain; background: #fff; padding: 10px; box-shadow: 0 0 30px rgba(0,0,0,0.7); position: relative; z-index: 2; }             .zs-lightbox-close { position: absolute; top: 20px; right: 30px; color: #fff; font-size: 40px; font-weight: bold; text-decoration: none; cursor: pointer; z-index: 3; line-height: 1; }             .zs-lightbox-close:hover { color: #ccc; }             .zs-lightbox-nav { position: absolute; top: 50%; transform: translateY(-50%); color: #fff; font-size: 50px; font-weight: bold; cursor: pointer; z-index: 3; padding: 20px; user-select: none; }             .zs-lightbox-nav:hover { color: #ccc; }             .zs-lightbox-prev { left: 20px; }             .zs-lightbox-next { right: 20px; }             .zs-lightbox-counter { position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%); color: #fff; font-size: 14px; z-index: 3; }         </style><script>
            (function() {
                var galleryId = "zs-gallery-699724b28c391";
                var currentIndex = 0;
                var lightboxes = [];
                var touchStartX = 0;
                var touchEndX = 0;
                
                function closeLightbox(e) {
                    if (e) e.preventDefault();
                    lightboxes.forEach(function(lb) { lb.classList.remove("active"); });
                }
                
                function showLightbox(index) {
                    lightboxes.forEach(function(lb) { lb.classList.remove("active"); });
                    if (lightboxes[index]) {
                        lightboxes[index].classList.add("active");
                        currentIndex = index;
                        updateCounter();
                    }
                }
                
                function nextImage(e) {
                    if (e) e.preventDefault();
                    var next = (currentIndex + 1) % lightboxes.length;
                    showLightbox(next);
                }
                
                function prevImage(e) {
                    if (e) e.preventDefault();
                    var prev = (currentIndex - 1 + lightboxes.length) % lightboxes.length;
                    showLightbox(prev);
                }
                
                function updateCounter() {
                    var counters = document.querySelectorAll("." + galleryId + " .zs-lightbox-counter");
                    counters.forEach(function(counter, idx) {
                        if (idx === currentIndex) {
                            counter.textContent = (currentIndex + 1) + " / " + lightboxes.length;
                        }
                    });
                }
                
                function handleTouchStart(e) {
                    touchStartX = e.changedTouches[0].screenX;
                }
                
                function handleTouchEnd(e) {
                    touchEndX = e.changedTouches[0].screenX;
                    handleSwipe();
                }
                
                function handleSwipe() {
                    if (touchEndX < touchStartX - 50) nextImage();
                    if (touchEndX > touchStartX + 50) prevImage();
                }
                
                document.addEventListener("DOMContentLoaded", function() {
                    lightboxes = Array.from(document.querySelectorAll(".zs-lightbox." + galleryId));
                    
                    var gallery = document.querySelector(".zs-event-media-gallery." + galleryId);
                    if (!gallery) return;
                    
                    gallery.querySelectorAll(".zs-gallery-open").forEach(function(opener, idx) {
                        opener.addEventListener("click", function(e) {
                            e.preventDefault();
                            showLightbox(idx);
                        });
                    });
                    
                    lightboxes.forEach(function(lightbox) {
                        lightbox.addEventListener("click", function(e) {
                            if (e.target === this) closeLightbox(e);
                        });
                        
                        lightbox.addEventListener("touchstart", handleTouchStart, false);
                        lightbox.addEventListener("touchend", handleTouchEnd, false);
                    });
                    
                    document.querySelectorAll(".zs-lightbox." + galleryId + " .zs-lightbox-close").forEach(function(closeBtn) {
                        closeBtn.addEventListener("click", closeLightbox);
                    });
                    
                    document.querySelectorAll(".zs-lightbox." + galleryId + " .zs-lightbox-prev").forEach(function(prevBtn) {
                        prevBtn.addEventListener("click", prevImage);
                    });
                    
                    document.querySelectorAll(".zs-lightbox." + galleryId + " .zs-lightbox-next").forEach(function(nextBtn) {
                        nextBtn.addEventListener("click", nextImage);
                    });
                    
                    document.addEventListener("keydown", function(e) {
                        var isActive = lightboxes.some(function(lb) { return lb.classList.contains("active"); });
                        if (!isActive) return;
                        
                        if (e.key === "Escape") closeLightbox(e);
                        if (e.key === "ArrowLeft") prevImage(e);
                        if (e.key === "ArrowRight") nextImage(e);
                    });
                });
            })();
